### Swift Convenience Initializers

Convenience initializers are secondary initializers that provide alternative ways to create an instance. They must call a designated initializer from the same class (delegation).

**Convenience Initializer Syntax:**

```swift
class ClassName {
    // Designated initializer
    init(parameter: Type) {
        // Set all properties
    }

    // Convenience initializer
    convenience init() {
        self.init(parameter: default)
    }
}
```

**Delegation Rules:**

| Rule | Description |
|------|-------------|
| Designated -> Super | Must call super's designated init |
| Convenience -> Self | Must call own designated init |
| Convenience -> Chain | Can chain to another convenience init |
| Final chain | Must eventually reach designated init |

```swift
class Rectangle {
    var width: Double
    var height: Double

    // Designated initializer
    init(width: Double, height: Double) {
        self.width = width
        self.height = height
    }

    // Convenience: square
    convenience init(side: Double) {
        self.init(width: side, height: side)
    }

    // Convenience: default
    convenience init() {
        self.init(width: 1.0, height: 1.0)
    }
}

let square = Rectangle(side: 5.0)
let defaultRect = Rectangle()
```

**Convenience Init Usage:**

```swift
class UIColor {
    // Designated
    init(red: Double, green: Double, blue: Double, alpha: Double) {
        // Setup
    }

    // Convenience: common colors
    convenience init(white: Double, alpha: Double) {
        self.init(red: white, green: white, blue: white, alpha: alpha)
    }

    convenience init(red: Double, green: Double, blue: Double) {
        self.init(red: red, green: green, blue: blue, alpha: 1.0)
    }
}
```

**When to Use:**

| Scenario | Example |
|----------|---------|
| Default values | `convenience init(url: String) { self.init(url: url, cachePolicy: .default) }` |
| Convenient inputs | `convenience init(json: [String: Any])` |
| Common configurations | `convenience init(credentials: Credentials)` |

> **Key Point:** Convenience initializers are optional. You can always use the designated initializer directly. Use convenience inits to reduce code duplication for common initialization patterns.

Designated initializers are the ones that do the actual setup. Convenience initializers delegate to them.

codeExample:
import Foundation

class Pizza {
    var size: String
    var crust: String
    var toppings: [String]

    // Designated
    init(size: String, crust: String, toppings: [String]) {
        self.size = size
        self.crust = crust
        self.toppings = toppings
    }

    // Convenience: margherita
    convenience init() {
        self.init(size: "Medium", crust: "Regular", toppings: ["Cheese", "Tomato Sauce"])
    }

    // Convenience: custom size with default toppings
    convenience init(size: String) {
        self.init(size: size, crust: "Regular", toppings: ["Cheese", "Tomato Sauce"])
    }

    // Convenience: all custom with default crust
    convenience init(size: String, toppings: [String]) {
        self.init(size: size, crust: "Regular", toppings: toppings)
    }

    func description() -> String {
        return "\(size) \(crust) crust pizza with \(toppings.joined(separator: ", "))"
    }
}

let margherita = Pizza()
let largeCustom = Pizza(size: "Large", toppings: ["Pepperoni", "Mushrooms", "Olives"])

print(margherita.description())
print(largeCustom.description())
